// ── Ghost site detection ──────────────────────────────────────────────────
// A ghost site has no active product in any domain (cadastro error / duplicate).
// These must be excluded from zone aggregations but remain visible in SitesView.
const isGhostSite = (siteName: string): boolean => {
  const siteProducts = SITE_PRODUCT_MAP[siteName as keyof typeof SITE_PRODUCT_MAP];
  if (!siteProducts) return true;
  return Object.values(siteProducts).every(d => d.products.length === 0);
};

// getDomainScore: resolve score for a site+domain
// Priority: SITE_PRODUCT_MAP.score (force-added computed) → MATURITY_DETAIL → L0 fallback → null
const getDomainScore = (siteName: string, domainKey: string): number | null => {
  const spm = (SITE_PRODUCT_MAP as Record<string, Record<string, { products: string[]; type: 'G'|'L'; dominant: string; score: number | null }>>)[siteName]?.[domainKey];
  if (spm?.score !== null && spm?.score !== undefined) return spm.score;
  const md = (MATURITY_DETAIL as Record<string, { zone: string; score: number; domains: Record<string, { score: number; type: string; levels: Record<string, unknown> } | null> }>)[siteName]?.domains?.[domainKey];
  if (md?.score !== null && md?.score !== undefined) return md.score;
  if (spm?.products?.length && spm.products.length > 0) return 0;
  return null; // sem produto
};

// MATURITY_DETAIL — N3/N4 capability-based maturity assessment (148 sites)
// Source: scripts/generate_maturity_detail.py from capability matrix
// N4 weights: Functional=2.0, Operational=1.0, Administrative=0.5
// Level gates: L1≥60%, L2≥75%, L3≥85%, L4≥90%
// ============================================================================
// MaturityDetailLevel, MaturityDetailDomain, MaturityDetailSite, KpiHistoryMonth, KpiHistoryData
// → moved to types/sites.ts and types/anaplan.ts (imported above)

// ── Sprint 9: OSE projection (linear regression) ──
function projectOse(history: { period: string; OSE: number }[], months: number): number | null {
  const n = history.length;
  if (n < 3) return null;
  const xs = history.map((_, i) => i);
  const ys = history.map(h => h.OSE);
  const sumX = xs.reduce((a, b) => a + b, 0);
  const sumY = ys.reduce((a, b) => a + b, 0);
  const sumXY = xs.reduce((s, x, i) => s + x * ys[i], 0);
  const sumX2 = xs.reduce((s, x) => s + x * x, 0);
  const denom = n * sumX2 - sumX * sumX;
  if (denom === 0) return null;
  const b = (n * sumXY - sumX * sumY) / denom;
  const a = (sumY - b * sumX) / n;
  return a + b * (n - 1 + months);
}
